// ============================================
// Parsea el evento de Evolution API
// Extrae datos del mensaje recibido
// ============================================

const body = $input.first().json.body || $input.first().json;

// Solo procesar eventos de mensaje nuevo
const event = body.event || '';
if (event !== 'messages.upsert') {
  return [{ json: { skip: true, reason: 'not_message_event', event } }];
}

const data = body.data || body;
const key = data.key || {};
const message = data.message || {};

// Extraer texto del mensaje (soporta varios tipos)
let texto = '';
if (message.conversation) {
  texto = message.conversation;
} else if (message.extendedTextMessage && message.extendedTextMessage.text) {
  texto = message.extendedTextMessage.text;
} else if (message.buttonsResponseMessage) {
  texto = message.buttonsResponseMessage.selectedDisplayText || '';
} else if (message.listResponseMessage) {
  texto = message.listResponseMessage.title || '';
}

// Si no hay texto, saltar (puede ser imagen, audio, etc)
if (!texto || texto.trim().length === 0) {
  return [{ json: { skip: true, reason: 'no_text_content' } }];
}

// Extraer número de WhatsApp
const remoteJid = key.remoteJid || '';

// Ignorar mensajes de grupos
if (remoteJid.includes('@g.us')) {
  return [{ json: { skip: true, reason: 'group_message' } }];
}

const whatsapp = remoteJid.replace('@s.whatsapp.net', '');

return [{
  json: {
    skip: false,
    whatsapp,
    texto: texto.trim(),
    fromMe: key.fromMe || false,
    messageId: key.id || '',
    pushName: data.pushName || '',
    timestamp: data.messageTimestamp || Math.floor(Date.now() / 1000)
  }
}];

// ============================================
// Combina datos del lead con el mensaje recibido
// Detecta si es un rechazo/negativa
// ============================================

const lead = $input.first().json;
const mensajeParsed = $('Parsear Mensaje').first().json;
const texto = mensajeParsed.texto;

// --- Detección de rechazo ---
const rechazos = [
  'no me interesa',
  'no gracias',
  'no, gracias',
  'no quiero',
  'dejen de escribir',
  'no me escriban',
  'no me contacten',
  'no me manden',
  'borrenme',
  'saquenme',
  'spam',
  'bloquear',
  'no thanks',
  'not interested',
  'stop',
  'basta',
  'dejen de joder',
  'no molesten'
];

const textoLower = texto.toLowerCase().trim();
const esRechazo = rechazos.some(r => textoLower.includes(r)) || 
                  textoLower === 'no' || 
                  textoLower === 'no.';

return [{
  json: {
    // Datos del lead (de la DB)
    id: lead.id,
    nombre: lead.nombre,
    rubro: lead.rubro,
    ciudad: lead.ciudad,
    whatsapp: lead.whatsapp,
    website: lead.website,
    status: lead.status,
    historial: lead.historial,
    // Datos del mensaje entrante
    texto_recibido: texto,
    pushName: mensajeParsed.pushName,
    // Análisis
    esRechazo
  }
}];

