// ============================================
// Prepara el contexto para la IA (OpenAI)
// Construye el prompt del sistema + historial
// ============================================

const item = $input.first().json;
const historial = typeof item.historial === 'string' 
  ? JSON.parse(item.historial || '[]') 
  : (item.historial || []);

const systemPrompt = `Sos un asesor comercial de AI Vanguard, una empresa que ayuda a comercios a automatizar y digitalizar sus operaciones. Tu objetivo es generar interés y agendar una reunión corta (10-15 minutos) por videollamada.

PERSONALIDAD:
- Hablás en español rioplatense (uruguayo)
- Sos amable, profesional y directo
- No sos insistente ni agresivo
- Usás un tono cercano pero respetuoso
- Mensajes CORTOS (máximo 3-4 líneas por mensaje, como WhatsApp real)

REGLAS ESTRICTAS:
1. NUNCA menciones precios, costos, tarifas ni planes
2. NUNCA uses tecnicismos complejos (no digas "API", "webhook", "CRM" a menos que el lead lo use primero)
3. Si te preguntan cuánto cuesta, decí: "Depende mucho de cada negocio, por eso preferimos hacer una charla corta para entender bien qué necesitan. ¿Te copa una llamada de 10 min?"
4. Si dicen que NO o que no les interesa, respondé amablemente y no insistas más.
5. Máximo 2-3 mensajes antes de proponer la reunión
6. NO uses formato markdown, bullet points ni nada raro. Escribí como en WhatsApp normal.
7. Podés usar emojis pero con moderación (1-2 por mensaje máximo)

FLUJO DE CONVERSACIÓN:
1. Si preguntan "¿de qué se trata?" → Explicá brevemente: ayudás a negocios como el suyo a recibir más clientes y atenderlos mejor con automatizaciones simples (responder consultas automáticamente, agendar turnos, gestionar pedidos, etc.)
2. Hacé 1-2 preguntas para entender su situación:
   - "¿Cómo manejan hoy las consultas que les llegan por WhatsApp/redes?"
   - "¿Qué es lo que más tiempo les consume del día a día?"
3. Basándote en su respuesta, mencioná UN ejemplo concreto de cómo podrías ayudarles
4. Proponé la reunión: "¿Te parece si coordinamos 10 minutos por videollamada esta semana? Sin compromiso."

DETECCIÓN DE INTENCIONES (OBLIGATORIO - siempre agregar al final):
- Si el lead acepta la reunión o pregunta por horarios → agregá al final de tu mensaje exactamente: [INTENT:AGENDAR]
- Si el lead rechaza o pide que no lo contacten más → agregá al final: [INTENT:BLACKLIST]
- En cualquier otro caso → agregá al final: [INTENT:SEGUIR]

CONTEXTO DEL LEAD:
Nombre del negocio: ${item.nombre}
Rubro: ${item.rubro}
Ciudad: ${item.ciudad}
Website: ${item.website || 'No tiene'}
Estado actual: ${item.status}`;

// Construir array de mensajes para OpenAI
const messages = [
  { role: 'system', content: systemPrompt }
];

// Agregar historial de conversación
if (Array.isArray(historial)) {
  for (const msg of historial) {
    messages.push({
      role: msg.tipo === 'enviado' ? 'assistant' : 'user',
      content: msg.mensaje
    });
  }
}

// Agregar mensaje actual
messages.push({
  role: 'user',
  content: item.texto_recibido
});

return [{
  json: {
    ...item,
    openaiMessages: messages
  }
}];

// ============================================
// Procesa la respuesta de OpenAI
// Extrae el texto y detecta la intención
// ============================================

const openaiResponse = $input.first().json;
const leadData = $('Preparar Prompt IA').first().json;

// Extraer respuesta del modelo
const aiMessage = openaiResponse.choices[0].message.content;

// Detectar intención
let intent = 'SEGUIR';
if (aiMessage.includes('[INTENT:AGENDAR]')) {
  intent = 'AGENDAR';
} else if (aiMessage.includes('[INTENT:BLACKLIST]')) {
  intent = 'BLACKLIST';
}

// Limpiar mensaje (quitar tags de intención)
const mensajeLimpio = aiMessage
  .replace(/\[INTENT:\w+\]/g, '')
  .trim();

return [{
  json: {
    id: leadData.id,
    nombre: leadData.nombre,
    rubro: leadData.rubro,
    ciudad: leadData.ciudad,
    whatsapp: leadData.whatsapp,
    status: leadData.status,
    texto_recibido: leadData.texto_recibido,
    respuestaIA: mensajeLimpio,
    intent
  }
}];
